{
  "goal": "总结今天有关于AI领域的新闻",
  "graph_policy": {
    "max_parallelism": 1,
    "fail_fast": true
  },
  "steps": [
    {
      "title": "获取新闻源",
      "instruction": "从可信的新闻网站或AI相关平台收集今天的所有AI领域新闻。",
      "depends_on": [],
      "input_bindings": []
    },
    {
      "title": "筛选与分类",
      "instruction": "根据新闻内容进行筛选，按主题（如技术突破、政策变化、行业动态等）分类。",
      "depends_on": ["S1"],
      "input_bindings": [
        {"from": "S1.output_text", "to": "news_sources"}
      ]
    },
    {
      "title": "总结关键信息",
      "instruction": "对每类新闻进行简要总结，提取关键信息与影响。",
      "depends_on": ["S2"],
      "input_bindings": [
        {"from": "S2.output_text", "to": "news_categories"}
      ]
    }
  ]
}
